// useGeolocation: small wrapper around navigator.geolocation with a built-in
// throttle for repeat refreshes (sessionStorage-backed) and friendly error
// messages. Designed for lightweight one-shot lookups, not continuous tracking.

import { useCallback, useState } from 'react';

const LOCATION_REFRESH_KEY = 'nearby_location_refresh_time';
const REFRESH_COOLDOWN_MINUTES = 30;

export interface GeoCoords {
  latitude: number;
  longitude: number;
}

export interface UseGeolocationResult {
  coords: GeoCoords;
  error?: string;
  inProgress: boolean;
  recentlyRefreshed: boolean;
  request: () => void;
  setCoords: (coords: GeoCoords) => void;
  setRecentlyRefreshed: (v: boolean) => void;
}

export function isLocationRecentlyRefreshed(): boolean {
  try {
    const last = sessionStorage.getItem(LOCATION_REFRESH_KEY);
    if (!last) return false;
    const diffMin = (Date.now() - Number(last)) / (1000 * 60);
    return diffMin < REFRESH_COOLDOWN_MINUTES;
  } catch {
    return false;
  }
}

export function saveLocationRefreshTime(): void {
  try {
    sessionStorage.setItem(LOCATION_REFRESH_KEY, Date.now().toString());
  } catch {
    /* ignore */
  }
}

function getGeoErrorMessage(err: GeolocationPositionError): string {
  switch (err.code) {
    case err.PERMISSION_DENIED:
      return 'Location permission denied. Please allow location access in your browser/app settings.';
    case err.POSITION_UNAVAILABLE:
      return 'Location unavailable. Please check that GPS/Location is turned ON.';
    case err.TIMEOUT:
      return 'Location request timed out. Please try again.';
    default:
      return 'Unable to access location. Please try again.';
  }
}

export { getGeoErrorMessage };

export function useGeolocation(initial?: GeoCoords): UseGeolocationResult {
  const [coords, setCoords] = useState<GeoCoords>(
    initial ?? { latitude: 0, longitude: 0 },
  );
  const [error, setError] = useState<string | undefined>(undefined);
  const [inProgress, setInProgress] = useState(false);
  const [recentlyRefreshed, setRecentlyRefreshed] = useState(false);

  const request = useCallback(() => {
    if (typeof navigator === 'undefined' || !navigator.geolocation) {
      setError('Geolocation is not supported by your browser.');
      return;
    }
    setError(undefined);
    setInProgress(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const { latitude, longitude } = pos.coords;
        setCoords({ latitude, longitude });
        saveLocationRefreshTime();
        setRecentlyRefreshed(true);
        setInProgress(false);
      },
      (err) => {
        setError(getGeoErrorMessage(err));
        setInProgress(false);
      },
      { enableHighAccuracy: true, timeout: 10000, maximumAge: 0 },
    );
  }, []);

  return { coords, error, inProgress, recentlyRefreshed, request, setCoords, setRecentlyRefreshed };
}
