import React, { useState, useCallback, useEffect, useRef } from 'react';
import { SectionHeading } from '@/components/ui/Typography';
import { Box, TextField, InputAdornment, Typography, IconButton, useMediaQuery, useTheme, Stack, Alert, Chip, CircularProgress, Menu, MenuItem, ListItemIcon, ListItemText, Autocomplete, FormControl, Select } from '@mui/material';
import { LoadingButton } from '@mui/lab';
import { Search, Clear, Refresh, SearchOff, VisibilityOff, TuneRounded, PersonOutlined, PlaceOutlined, BusinessOutlined, WorkOutlined, SchoolOutlined, LocalLibraryOutlined, PhoneOutlined, EmailOutlined, CalendarMonthOutlined, StorefrontOutlined, GroupOutlined, MyLocation as MyLocationIcon, LocationOn as LocationOnIcon } from '@mui/icons-material';
import { Schools } from '@/constants/StaticData';
import { useNavigate, useSearch } from '@tanstack/react-router';
import { StatusMessage } from '@/components/StatusMessage';
import { InfiniteScrollList } from '@/components/InfiniteScrollList';
import { EmptyState } from '@/components/ui/EmptyState';
import { CallStatus, Roles } from '@/types/api.types';
import { getApiError } from '@/utils/apiError';
import { GetUserRoles } from '@/utils/token';
import { useProfilesStore } from '@/store';
import { ApiGlobalStateManager } from '@/lib/api-state';

import { ProfileServices, ProfileServicesError, BusinessServicesError, SearchServices, SearchServicesError } from '@/api';
import { PersonDisplay } from './PersonDisplay';
import { BusinessCard } from '@/components/BusinessCard';
import { PublicProfileResult, AdvancedSearchProfilePayload } from '@/types/profile.types';
import { BusinessResult } from '@/types/business.types';
import { UnifiedSearchResult } from '@/types/search.types';
import { isLocationRecentlyRefreshed, saveLocationRefreshTime, getGeoErrorMessage } from '@/hooks/useGeolocation';

const PAGE_SIZE = 20;

const UnifiedSearch: React.FunctionComponent = () => {
    const { profileState, setProfileState } = useProfilesStore();
    const navigate = useNavigate();
    const searchParams = useSearch({ strict: false }) as Record<string, string | undefined>;

    // Read initial state from query params
    const initialQ = searchParams.q || '';
    const initialKey = (searchParams.k || 'searchText') as keyof AdvancedSearchProfilePayload | '' | 'business' | 'jnvBatch' | 'nearby';
    const initialJnv = searchParams.j || '';
    const initialBatch = searchParams.b ? Number(searchParams.b) : '';

    // Load profile if not yet loaded (for contact visibility check)
    useEffect(() => {
        if (profileState.status === CallStatus.NotStarted) {
            ApiGlobalStateManager(ProfileServices.GetProfile(), setProfileState);
        }
    }, [profileState.status, setProfileState]);

    const isProfileLoaded = profileState?.status === CallStatus.Success;
    const isOwnContactVisible = isProfileLoaded && (profileState?.data?.isContactInfoVisible ?? false);

    const [searchQuery, setSearchQuery] = useState<string>(initialQ);
    const [searchKey, setSearchKey] = useState<keyof AdvancedSearchProfilePayload | '' | 'business' | 'jnvBatch' | 'nearby'>(initialKey);

    const [filterAnchorEl, setFilterAnchorEl] = useState<null | HTMLElement>(null);

    // JNV + Batch combo state (admin only)
    const [selectedSchoolName, setSelectedSchoolName] = useState<string>(initialJnv);
    const [selectedEntryYear, setSelectedEntryYear] = useState<number | ''>(initialBatch);

    // Nearby search state
    const [nearbyRange, setNearbyRange] = useState<number>(5);
    const [geoLocation, setGeoLocation] = useState<{ latitude: number; longitude: number }>({ latitude: 0, longitude: 0 });
    const [geoError, setGeoError] = useState<string | undefined>(undefined);
    const [geoInProgress, setGeoInProgress] = useState<boolean>(false);
    const [hasTriedLocationUpdate, setHasTriedLocationUpdate] = useState<boolean>(false);
    const [locationRecentlyRefreshed, setLocationRecentlyRefreshed] = useState<boolean>(false);

    const [searchStatus, setSearchStatus] = useState<CallStatus>(CallStatus.NotStarted);
    const [error, setError] = useState<string | undefined>(undefined);
    const [correlationId, setCorrelationId] = useState<string | undefined>(undefined);

    // Profile results
    const [profileResults, setProfileResults] = useState<PublicProfileResult[]>([]);
    const [profileHasMore, setProfileHasMore] = useState<boolean>(false);
    const [profileContinuationToken, setProfileContinuationToken] = useState<string | undefined>(undefined);
    const [profilePageNumber, setProfilePageNumber] = useState<number>(1);
    const [profileLoadingMore, setProfileLoadingMore] = useState<boolean>(false);

    // Business results
    const [businessResults, setBusinessResults] = useState<BusinessResult[]>([]);
    const [businessHasMore, setBusinessHasMore] = useState<boolean>(false);
    const [businessContinuationToken, setBusinessContinuationToken] = useState<string | undefined>(undefined);
    const [businessPageNumber, setBusinessPageNumber] = useState<number>(1);
    const [businessLoadingMore, setBusinessLoadingMore] = useState<boolean>(false);

    const [lastSearchQuery, setLastSearchQuery] = useState<string>('');
    const [lastSearchKey, setLastSearchKey] = useState<keyof AdvancedSearchProfilePayload | '' | 'business' | 'jnvBatch' | 'nearby'>('');

    // Admin index
    const [profileIndexStatus, setProfileIndexStatus] = useState<CallStatus>(CallStatus.NotStarted);
    const [businessIndexStatus, setBusinessIndexStatus] = useState<CallStatus>(CallStatus.NotStarted);
    const [indexMessage, setIndexMessage] = useState<string>('');

    const userRoles = GetUserRoles();
    const isAdmin = userRoles.includes(Roles.Admin) || userRoles.includes(Roles.SuperAdmin);
    const isSchoolAdmin = userRoles.includes(Roles.SchoolAdmin);
    const theme = useTheme();
    const isMobile = useMediaQuery(theme.breakpoints.down('sm'));

    // Advanced search key options
    const jnvBatchLabel = isAdmin ? 'By JNV & Batch (Admin)' : isSchoolAdmin ? 'By JNV & Batch' : 'My Batchmates';
    const searchKeys = [
        { value: 'searchText', label: 'By Any Details' },
        { value: 'nearby', label: 'NearBy Alumni' },
        { value: 'business', label: 'By Alumni Business' },
        { value: 'jnvBatch', label: jnvBatchLabel },
        { value: 'name', label: 'By Name' },
        { value: 'location', label: 'By Location' },
        { value: 'organisation', label: 'By organisation' },
        { value: 'jobTitle', label: 'By Job Title' },
        { value: 'university', label: 'By University' },
        { value: 'degree', label: 'By Degree' },
        ...(isAdmin ? [
            { value: 'phone', label: 'By Phone (Admin)' },
            { value: 'email', label: 'By Email (Admin)' },
            { value: 'entryYear', label: 'By Entry Year (Admin)' },
            { value: 'exitYear', label: 'By Exit Year (Admin)' }
        ] as const : [])
    ];

    const numericSearchKeys: Array<keyof AdvancedSearchProfilePayload> = ['entryYear', 'exitYear'];
    const toSearchValue = (key: keyof AdvancedSearchProfilePayload, val: string) =>
        numericSearchKeys.includes(key) ? parseInt(val, 10) : val;

    const isAdvancedFieldSearch = searchKey !== 'searchText' && searchKey !== '' && searchKey !== 'business' && searchKey !== 'jnvBatch' && searchKey !== 'nearby';
    const isBusinessOnlySearch = searchKey === 'business';
    const isJnvBatchSearch = searchKey === 'jnvBatch';
    const isNearbySearch = searchKey === 'nearby';

    // Icon for the active filter
    const filterIconMap: Record<string, React.ReactNode> = {
        searchText: <TuneRounded fontSize="small" />,
        business: <StorefrontOutlined fontSize="small" />,
        jnvBatch: <GroupOutlined fontSize="small" />,
        nearby: <MyLocationIcon fontSize="small" />,
        name: <PersonOutlined fontSize="small" />,
        location: <PlaceOutlined fontSize="small" />,
        organisation: <BusinessOutlined fontSize="small" />,
        jobTitle: <WorkOutlined fontSize="small" />,
        university: <SchoolOutlined fontSize="small" />,
        degree: <LocalLibraryOutlined fontSize="small" />,
        phone: <PhoneOutlined fontSize="small" />,
        email: <EmailOutlined fontSize="small" />,
        entryYear: <CalendarMonthOutlined fontSize="small" />,
        exitYear: <CalendarMonthOutlined fontSize="small" />,
    };
    const activeFilterIcon = (isAdvancedFieldSearch || isBusinessOnlySearch || isJnvBatchSearch || isNearbySearch) && searchKey ? filterIconMap[searchKey] : <TuneRounded fontSize="small" />;

    // Dynamic placeholder based on active filter
    const placeholderMap: Record<string, string> = {
        searchText: 'Search alumni, businesses...',
        business: 'Search alumni businesses...',
        name: 'Search alumni by name...',
        location: 'Search alumni by location...',
        organisation: 'Search alumni by organisation...',
        jobTitle: 'Search alumni by job title...',
        university: 'Search alumni by university...',
        degree: 'Search alumni by degree...',
        phone: 'Search alumni by phone...',
        email: 'Search alumni by email...',
        entryYear: 'Search alumni by entry year...',
        exitYear: 'Search alumni by exit year...',
    };
    const searchPlaceholder = ((isAdvancedFieldSearch || isBusinessOnlySearch || isJnvBatchSearch) && searchKey) ? placeholderMap[searchKey] || placeholderMap.searchText : placeholderMap.searchText;

    // Restore cached location when entering Nearby mode if recently refreshed
    useEffect(() => {
        if (!isNearbySearch) return;
        const lat = profileState.data?.latitude;
        const lon = profileState.data?.longitude;
        if (isLocationRecentlyRefreshed() && lat && lat > 0 && lon && lon > 0) {
            setLocationRecentlyRefreshed(true);
            setGeoLocation({ latitude: lat, longitude: lon });
        }
    }, [isNearbySearch, profileState.data?.latitude, profileState.data?.longitude]);

    // Get GPS position; persist to profile if stale or missing
    const updateGeoLocation = useCallback(() => {
        if (!navigator.geolocation) {
            setGeoError('Geolocation is not supported by your browser.');
            return;
        }
        setGeoInProgress(true);
        setGeoError(undefined);
        setHasTriedLocationUpdate(true);
        navigator.geolocation.getCurrentPosition(
            (position) => {
                const { latitude, longitude } = position.coords;
                setGeoLocation({ latitude, longitude });

                const lastUpdate = profileState.data?.modifiedAt ? new Date(profileState.data.modifiedAt) : new Date(0);
                const diffMinutes = Math.ceil((Date.now() - lastUpdate.getTime()) / (1000 * 60));
                const needsPersist = diffMinutes > 10 || !profileState.data?.latitude || !profileState.data?.longitude;
                if (needsPersist) {
                    ApiGlobalStateManager(ProfileServices.UpdateProfileGeo({ latitude, longitude }), setProfileState).then(() => {
                        saveLocationRefreshTime();
                        setLocationRecentlyRefreshed(true);
                        setGeoInProgress(false);
                    });
                } else {
                    saveLocationRefreshTime();
                    setLocationRecentlyRefreshed(true);
                    setGeoInProgress(false);
                }
            },
            (err) => {
                setGeoError(getGeoErrorMessage(err));
                setGeoInProgress(false);
            },
            { enableHighAccuracy: true, timeout: 15000, maximumAge: 300000 }
        );
    }, [profileState.data?.latitude, profileState.data?.longitude, profileState.data?.modifiedAt, setProfileState]);

    // Update URL query params without navigation
    const updateUrlParams = useCallback((params: Record<string, string | undefined>) => {
        const filtered: Record<string, string> = {};
        for (const [k, v] of Object.entries(params)) {
            if (v) filtered[k] = v;
        }
        navigate({ search: () => filtered, replace: true } as any);
    }, [navigate]);

    // Execute search
    const executeSearch = useCallback(async () => {
        if (isJnvBatchSearch) {
            if (!selectedSchoolName || !selectedEntryYear) return;
        } else if (isNearbySearch) {
            if (!geoLocation.latitude || !geoLocation.longitude) return;
        } else {
            const trimmedQuery = searchQuery.trim();
            if (trimmedQuery.length === 0) return;
        }

        const trimmedQuery = isJnvBatchSearch
            ? `${selectedSchoolName} (${selectedEntryYear})`
            : isNearbySearch
                ? `Within ${nearbyRange} km`
                : searchQuery.trim();

        setSearchStatus(CallStatus.InProgress);
        setError(undefined);
        setCorrelationId(undefined);
        setLastSearchQuery(trimmedQuery);
        setLastSearchKey(isJnvBatchSearch ? 'jnvBatch' : isNearbySearch ? 'nearby' : isBusinessOnlySearch ? 'business' : isAdvancedFieldSearch ? searchKey : 'searchText');
        setProfilePageNumber(1);
        setProfileContinuationToken(undefined);
        setBusinessPageNumber(1);
        setBusinessContinuationToken(undefined);

        // Sync to URL (skip for nearby — session-scoped)
        updateUrlParams({
            q: isJnvBatchSearch || isNearbySearch ? undefined : searchQuery.trim(),
            k: searchKey !== 'searchText' ? searchKey : undefined,
            j: isJnvBatchSearch ? selectedSchoolName : undefined,
            b: isJnvBatchSearch && selectedEntryYear ? String(selectedEntryYear) : undefined,
        });

        try {
            if (isNearbySearch) {
                // Nearby: profile-only search via unified /search with geo filter; ordered by distance.
                const response = await SearchServices.UnifiedSearch('', {
                    pageNumber: 1,
                    pageSize: PAGE_SIZE,
                    lat: geoLocation.latitude,
                    lng: geoLocation.longitude,
                    radiusKm: nearbyRange,
                });

                if (response.data.status >= 200 && response.data.status < 300) {
                    const result: UnifiedSearchResult = response.data.result;
                    setProfileResults(result.profiles?.items || []);
                    setProfileHasMore(result.profiles?.hasNextPage ?? false);
                    setProfileContinuationToken(result.profiles?.continuationToken);
                    setBusinessResults([]);
                    setBusinessHasMore(false);
                    setSearchStatus(CallStatus.Success);
                } else {
                    setError(SearchServicesError.UnifiedSearchError(response.data.status));
                    setProfileResults([]);
                    setBusinessResults([]);
                    setProfileHasMore(false);
                    setBusinessHasMore(false);
                    setSearchStatus(CallStatus.Failure);
                }
            } else if (isJnvBatchSearch) {
                // JNV + Batch search via unified /search with schoolName + entryYear filters.
                // Server enforces role-based scope (admin: any, schoolAdmin: own school, user: own school+batch).
                const response = await SearchServices.UnifiedSearch('', {
                    pageNumber: 1,
                    pageSize: PAGE_SIZE,
                    schoolName: selectedSchoolName || undefined,
                    entryYear: selectedEntryYear as number,
                });

                if (response.data.status >= 200 && response.data.status < 300) {
                    const result: UnifiedSearchResult = response.data.result;
                    setProfileResults(result.profiles?.items || []);
                    setProfileHasMore(result.profiles?.hasNextPage ?? false);
                    setProfileContinuationToken(result.profiles?.continuationToken);
                    setBusinessResults([]);
                    setBusinessHasMore(false);
                    setSearchStatus(CallStatus.Success);
                } else {
                    setError(SearchServicesError.UnifiedSearchError(response.data.status));
                    setProfileResults([]);
                    setBusinessResults([]);
                    setProfileHasMore(false);
                    setBusinessHasMore(false);
                    setSearchStatus(CallStatus.Failure);
                }
            } else if (isBusinessOnlySearch) {
                // Business-only search via unified /search; show only the businesses pane.
                const response = await SearchServices.UnifiedSearch(trimmedQuery, {
                    pageNumber: 1,
                    pageSize: PAGE_SIZE,
                });

                if (response.data.status >= 200 && response.data.status < 300) {
                    const result: UnifiedSearchResult = response.data.result;
                    setProfileResults([]);
                    setProfileHasMore(false);
                    setBusinessResults(result.businesses?.items || []);
                    setBusinessHasMore(result.businesses?.hasNextPage ?? false);
                    setBusinessContinuationToken(result.businesses?.continuationToken);
                    setSearchStatus(CallStatus.Success);
                } else {
                    setError(BusinessServicesError.SearchBusinessError(response.data.status));
                    setProfileResults([]);
                    setBusinessResults([]);
                    setProfileHasMore(false);
                    setBusinessHasMore(false);
                    setSearchStatus(CallStatus.Failure);
                }
            } else if (isAdvancedFieldSearch) {
                // Advanced mode: profile-only search via field-specific API
                const advancedPayload: AdvancedSearchProfilePayload = {
                    pageNumber: 1,
                    pageSize: PAGE_SIZE,
                    continuationToken: undefined,
                    [searchKey]: toSearchValue(searchKey as keyof AdvancedSearchProfilePayload, trimmedQuery)
                };
                const response = await ProfileServices.AdvancedSearchProfile(advancedPayload);

                if (response.data.status >= 200 && response.data.status < 300) {
                    const result = response.data.result;
                    const profilesPage = result?.profiles;
                    setProfileResults(profilesPage?.items || []);
                    setProfileHasMore(profilesPage?.hasNextPage ?? false);
                    setProfileContinuationToken(profilesPage?.continuationToken);
                    setBusinessResults([]);
                    setBusinessHasMore(false);
                    setSearchStatus(CallStatus.Success);
                } else {
                    setError(ProfileServicesError.SearchProfileError(response.data.status));
                    setProfileResults([]);
                    setBusinessResults([]);
                    setProfileHasMore(false);
                    setBusinessHasMore(false);
                    setSearchStatus(CallStatus.Failure);
                }
            } else {
                // Unified search: both profiles and businesses
                const response = await SearchServices.UnifiedSearch(trimmedQuery, {
                    pageNumber: 1,
                    pageSize: PAGE_SIZE,
                });

                if (response.data.status >= 200 && response.data.status < 300) {
                    const result: UnifiedSearchResult = response.data.result;
                    setProfileResults(result.profiles?.items || []);
                    setProfileHasMore(result.profiles?.hasNextPage ?? false);
                    setProfileContinuationToken(result.profiles?.continuationToken);
                    setBusinessResults(result.businesses?.items || []);
                    setBusinessHasMore(result.businesses?.hasNextPage ?? false);
                    setBusinessContinuationToken(result.businesses?.continuationToken);
                    setSearchStatus(CallStatus.Success);
                } else {
                    setError(SearchServicesError.UnifiedSearchError(response.data.status));
                    setProfileResults([]);
                    setBusinessResults([]);
                    setProfileHasMore(false);
                    setBusinessHasMore(false);
                    setSearchStatus(CallStatus.Failure);
                }
            }
        } catch (err) {
            const apiErr = getApiError(err);
            const status = apiErr.httpStatus;
            setError(isBusinessOnlySearch
                ? BusinessServicesError.SearchBusinessError(status)
                : isAdvancedFieldSearch || isJnvBatchSearch
                ? ProfileServicesError.SearchProfileError(status)
                : SearchServicesError.UnifiedSearchError(status));
            setCorrelationId(apiErr.correlationId);
            setProfileResults([]);
            setBusinessResults([]);
            setProfileHasMore(false);
            setBusinessHasMore(false);
            setSearchStatus(CallStatus.Failure);
        }
    }, [searchQuery, searchKey, isAdvancedFieldSearch, isBusinessOnlySearch, isJnvBatchSearch, isNearbySearch, selectedSchoolName, selectedEntryYear, geoLocation.latitude, geoLocation.longitude, nearbyRange]);

    // Auto-search on mount if query params are present
    const hasAutoSearched = useRef(false);
    useEffect(() => {
        if (hasAutoSearched.current) return;
        const hasParams = initialQ || (initialKey === 'jnvBatch' && initialJnv && initialBatch);
        if (hasParams) {
            hasAutoSearched.current = true;
            executeSearch();
        }
    }, [executeSearch, initialQ, initialKey, initialJnv, initialBatch]);

    // Load more profiles
    const loadMoreProfiles = useCallback(async () => {
        if (profileLoadingMore || !profileHasMore) return;

        setProfileLoadingMore(true);
        const nextPage = profilePageNumber + 1;

        try {
            let response;

            if (lastSearchKey === 'nearby') {
                const r = await SearchServices.UnifiedSearch('', {
                    pageNumber: nextPage,
                    pageSize: PAGE_SIZE,
                    lat: geoLocation.latitude,
                    lng: geoLocation.longitude,
                    radiusKm: nearbyRange,
                });
                if (r.data.status >= 200 && r.data.status < 300) {
                    const profilesPage = r.data.result?.profiles;
                    setProfileResults(prev => [...prev, ...(profilesPage?.items || [])]);
                    setProfileHasMore(profilesPage?.hasNextPage ?? false);
                    setProfileContinuationToken(profilesPage?.continuationToken);
                    setProfilePageNumber(nextPage);
                }
                return;
            }
            if (lastSearchKey === 'jnvBatch') {
                const r = await SearchServices.UnifiedSearch('', {
                    pageNumber: nextPage,
                    pageSize: PAGE_SIZE,
                    schoolName: selectedSchoolName || undefined,
                    entryYear: selectedEntryYear as number,
                });
                if (r.data.status >= 200 && r.data.status < 300) {
                    const profilesPage = r.data.result?.profiles;
                    setProfileResults(prev => [...prev, ...(profilesPage?.items || [])]);
                    setProfileHasMore(profilesPage?.hasNextPage ?? false);
                    setProfileContinuationToken(profilesPage?.continuationToken);
                    setProfilePageNumber(nextPage);
                }
                return;
            }
            if (lastSearchKey !== 'searchText' && lastSearchKey !== '') {
                const advancedPayload: AdvancedSearchProfilePayload = {
                    pageNumber: nextPage,
                    pageSize: PAGE_SIZE,
                    continuationToken: profileContinuationToken,
                    [lastSearchKey]: toSearchValue(lastSearchKey as keyof AdvancedSearchProfilePayload, lastSearchQuery)
                };
                response = await ProfileServices.AdvancedSearchProfile(advancedPayload);
            } else {
                response = await ProfileServices.SearchProfile(lastSearchQuery, {
                    pageNumber: nextPage,
                    pageSize: PAGE_SIZE,
                    continuationToken: profileContinuationToken
                });
            }

            if (response.data.status >= 200 && response.data.status < 300) {
                const result = response.data.result;
                const profilesPage = result?.profiles;
                setProfileResults(prev => [...prev, ...(profilesPage?.items || [])]);
                setProfileHasMore(profilesPage?.hasNextPage ?? false);
                setProfileContinuationToken(profilesPage?.continuationToken);
                setProfilePageNumber(nextPage);
            }
        } catch {
            // Silently fail; user can scroll again to retry
        } finally {
            setProfileLoadingMore(false);
        }
    }, [profileLoadingMore, profileHasMore, profilePageNumber, lastSearchKey, lastSearchQuery, profileContinuationToken, selectedSchoolName, selectedEntryYear, geoLocation.latitude, geoLocation.longitude, nearbyRange]);

    // Load more businesses
    const loadMoreBusinesses = useCallback(async () => {
        if (businessLoadingMore || !businessHasMore) return;

        setBusinessLoadingMore(true);
        const nextPage = businessPageNumber + 1;

        try {
            const response = await SearchServices.UnifiedSearch(lastSearchQuery, {
                pageNumber: nextPage,
                pageSize: PAGE_SIZE,
            });

            if (response.data.status >= 200 && response.data.status < 300) {
                const businessesPage = response.data.result?.businesses;
                setBusinessResults(prev => [...prev, ...(businessesPage?.items || [])]);
                setBusinessHasMore(businessesPage?.hasNextPage ?? false);
                setBusinessContinuationToken(businessesPage?.continuationToken);
                setBusinessPageNumber(nextPage);
            }
        } catch {
            // Silently fail; user can scroll again to retry
        } finally {
            setBusinessLoadingMore(false);
        }
    }, [businessLoadingMore, businessHasMore, businessPageNumber, lastSearchQuery, businessContinuationToken]);

    const handleClearSearch = () => {
        setSearchQuery('');
        setSelectedSchoolName('');
        setSelectedEntryYear('');
        setProfileResults([]);
        setBusinessResults([]);
        setLastSearchQuery('');
        setLastSearchKey('');
        setSearchKey('searchText');
        setError(undefined);
        setSearchStatus(CallStatus.NotStarted);
        setProfileHasMore(false);
        setProfileContinuationToken(undefined);
        setProfilePageNumber(1);
        setBusinessHasMore(false);
        setBusinessContinuationToken(undefined);
        setBusinessPageNumber(1);
        setGeoError(undefined);
        setHasTriedLocationUpdate(false);
        updateUrlParams({});
    };

    // Reset state when URL params are cleared (e.g. navigating to home)
    useEffect(() => {
        const hasParams = searchParams.q || searchParams.k || searchParams.j || searchParams.b;
        if (!hasParams && searchStatus !== CallStatus.NotStarted) {
            setSearchQuery('');
            setSelectedSchoolName('');
            setSelectedEntryYear('');
            setProfileResults([]);
            setBusinessResults([]);
            setLastSearchQuery('');
            setLastSearchKey('');
            setSearchKey('searchText');
            setError(undefined);
            setSearchStatus(CallStatus.NotStarted);
            setProfileHasMore(false);
            setProfileContinuationToken(undefined);
            setProfilePageNumber(1);
            setBusinessHasMore(false);
            setBusinessContinuationToken(undefined);
            setBusinessPageNumber(1);
        }
    }, [searchParams.q, searchParams.k, searchParams.j, searchParams.b]);

    const handleGenerateIndex = useCallback(async (type: 'profile' | 'business') => {
        const setStatus = type === 'profile' ? setProfileIndexStatus : setBusinessIndexStatus;
        setStatus(CallStatus.InProgress);
        setIndexMessage('');
        try {
            const response = type === 'profile'
                ? await SearchServices.IndexProfiles()
                : await SearchServices.IndexBusinesses();
            if (response.data.status >= 200 && response.data.status < 300) {
                setIndexMessage(`${type === 'profile' ? 'Profile' : 'Business'} index generation submitted.`);
                setStatus(CallStatus.Success);
            } else {
                setIndexMessage(`Failed to generate ${type} index.`);
                setStatus(CallStatus.Failure);
            }
        } catch {
            setIndexMessage(`Failed to generate ${type} index. Please try again.`);
            setStatus(CallStatus.Failure);
        }
    }, []);

    const hasProfileResults = profileResults.length > 0;
    const hasBusinessResults = businessResults.length > 0;
    const hasAnyResults = hasProfileResults || hasBusinessResults;
    const shouldShowResults = lastSearchQuery.length > 0 && hasAnyResults;
    const shouldShowNoResults = lastSearchQuery.length > 0 && searchStatus === CallStatus.Success && !hasAnyResults;
    const shouldShowEmptyState = lastSearchQuery.length === 0 && searchStatus === CallStatus.NotStarted;
    const isSearching = searchStatus === CallStatus.InProgress;

    const totalResultCount = profileResults.length + businessResults.length;
    const totalHasMore = profileHasMore || businessHasMore;

    return (
        <Box sx={{ maxWidth: 720, mx: 'auto', px: { xs: 1, sm: 2 } }}>
            {/* Google-style centered search area */}
            <Box sx={{
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                pt: shouldShowEmptyState ? 4 : 1,
                pb: 2,
                transition: 'padding 0.3s ease',
            }}>
                {/* Logo / Title */}
                {shouldShowEmptyState && (
                    <Typography
                        variant="h4"
                        sx={{
                            fontWeight: 700,
                            mb: 3,
                            background: 'linear-gradient(135deg, #1976d2 0%, #42a5f5 50%, #1565c0 100%)',
                            WebkitBackgroundClip: 'text',
                            WebkitTextFillColor: 'transparent',
                            letterSpacing: '-0.5px',
                        }}
                    >
                        Navodaya Search
                    </Typography>
                )}

                {/* Search Bar — pill shaped, JNV+Batch dropdowns, Nearby controls, or Elevated Roles */}
                <Box sx={{ width: '100%', maxWidth: 580, px: isMobile ? 1 : 0 }}>
                    {isNearbySearch ? (
                        /* Nearby: get-location button → range + search */
                        <Box sx={{
                            display: 'flex',
                            gap: 1,
                            alignItems: 'center',
                            bgcolor: '#ffffff',
                            border: '1px solid #dfe1e5',
                            borderRadius: '24px',
                            height: isMobile ? 48 : 52,
                            px: 1,
                            '&:hover': {
                                boxShadow: '0 2px 8px 1px rgba(64,60,67,.16)',
                                borderColor: 'transparent',
                            },
                        }}>
                            <IconButton
                                size="small"
                                onClick={(e) => setFilterAnchorEl(e.currentTarget)}
                                sx={{ color: '#fff', bgcolor: 'primary.main', '&:hover': { bgcolor: 'primary.dark' } }}
                                title="Change filter"
                            >
                                <MyLocationIcon fontSize="small" />
                            </IconButton>
                            {!locationRecentlyRefreshed || !geoLocation.latitude ? (
                                <LoadingButton
                                    loadingPosition="start"
                                    loading={geoInProgress}
                                    disabled={geoInProgress}
                                    variant="contained"
                                    onClick={updateGeoLocation}
                                    startIcon={<MyLocationIcon />}
                                    sx={{ textTransform: 'none', borderRadius: 2 }}
                                >
                                    Get My Location
                                </LoadingButton>
                            ) : (
                                <>
                                    <FormControl size="small" variant="standard" sx={{ flex: 1, minWidth: 130 }}>
                                        <Select
                                            value={nearbyRange}
                                            onChange={(e) => setNearbyRange(Number(e.target.value))}
                                            disableUnderline
                                            sx={{ fontSize: '0.875rem' }}
                                        >
                                            {[1, 2, 5, 10, 20, 50, 100, 200, 500, 1000, 5000].map(km => (
                                                <MenuItem key={km} value={km}>Within {km} km</MenuItem>
                                            ))}
                                        </Select>
                                    </FormControl>
                                    {isSearching ? (
                                        <CircularProgress size={20} sx={{ mx: 0.5 }} />
                                    ) : (
                                        <IconButton
                                            size="small"
                                            onClick={executeSearch}
                                            color="primary"
                                        >
                                            <Search />
                                        </IconButton>
                                    )}
                                </>
                            )}
                        </Box>
                    ) : isJnvBatchSearch ? (
                        /* JNV + Batch combo dropdowns */
                        <Box sx={{
                            display: 'flex',
                            gap: 1,
                            alignItems: 'center',
                            bgcolor: '#ffffff',
                            border: '1px solid #dfe1e5',
                            borderRadius: '24px',
                            height: isMobile ? 48 : 52,
                            px: 1,
                            '&:hover': {
                                boxShadow: '0 2px 8px 1px rgba(64,60,67,.16)',
                                borderColor: 'transparent',
                            },
                        }}>
                            <IconButton
                                size="small"
                                onClick={(e) => setFilterAnchorEl(e.currentTarget)}
                                sx={{ color: '#fff', bgcolor: 'primary.main', '&:hover': { bgcolor: 'primary.dark' } }}
                                title="Change filter"
                            >
                                <GroupOutlined fontSize="small" />
                            </IconButton>
                            <Autocomplete
                                size="small"
                                disabled={!isAdmin}
                                options={(() => {
                                    const userJnvId = profileState?.data?.firstJnvId;
                                    if (!userJnvId) return Schools;
                                    return [...Schools].sort((a, b) => {
                                        if (a.UniqueId === userJnvId) return -1;
                                        if (b.UniqueId === userJnvId) return 1;
                                        return 0;
                                    });
                                })()}
                                getOptionLabel={(option) => `[${option.StatePrefix}] ${option.SchoolName}`}
                                value={Schools.find(s => `JNV ${s.SchoolName} ${s.StatePrefix}` === selectedSchoolName) || null}
                                onChange={(_e, val) => setSelectedSchoolName(val ? `JNV ${val.SchoolName} ${val.StatePrefix}` : '')}
                                renderInput={(params) => (
                                    <TextField {...params} placeholder="Select School" variant="standard" slotProps={{ ...params.slotProps, input: { ...params.slotProps?.input, disableUnderline: true } }} />
                                )}
                                sx={{ flex: 1, '& .MuiInputBase-root': { py: 0 } }}
                                disableClearable={!selectedSchoolName}
                            />
                            <FormControl size="small" variant="standard" sx={{ minWidth: 70 }}>
                                <Select
                                    value={selectedEntryYear}
                                    onChange={(e) => setSelectedEntryYear(e.target.value as number)}
                                    disabled={!isAdmin && !isSchoolAdmin}
                                    displayEmpty
                                    disableUnderline
                                    sx={{ fontSize: '0.875rem' }}
                                >
                                    <MenuItem value="" disabled>Batch</MenuItem>
                                    {Array.from({ length: new Date().getFullYear() - 1985 + 1 }, (_, i) => 1985 + i).map(year => (
                                        <MenuItem key={year} value={year}>{year}</MenuItem>
                                    ))}
                                </Select>
                            </FormControl>
                            {isSearching ? (
                                <CircularProgress size={20} sx={{ mx: 0.5 }} />
                            ) : (
                                <IconButton
                                    size="small"
                                    onClick={executeSearch}
                                    disabled={!selectedSchoolName || !selectedEntryYear}
                                    color="primary"
                                >
                                    <Search />
                                </IconButton>
                            )}
                        </Box>
                    ) : (
                    <>
                    <TextField
                        fullWidth
                        placeholder={searchPlaceholder}
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        onKeyDown={(e) => { if (e.key === 'Enter') { e.preventDefault(); executeSearch(); } }}
                        disabled={isSearching}
                        sx={{
                            '& .MuiOutlinedInput-root': {
                                borderRadius: '24px',
                                height: isMobile ? 48 : 52,
                                px: 1,
                                bgcolor: '#ffffff',
                                border: '1px solid #dfe1e5',
                                boxShadow: 'none',
                                '&:hover': {
                                    bgcolor: '#ffffff',
                                    boxShadow: '0 2px 8px 1px rgba(64,60,67,.16)',
                                    borderColor: 'transparent',
                                },
                                '&.Mui-focused': {
                                    bgcolor: '#ffffff',
                                    boxShadow: '0 2px 8px 1px rgba(64,60,67,.16)',
                                    borderColor: 'transparent',
                                },
                                '& fieldset': { border: 'none' },
                            },
                        }}
                        slotProps={{
                            input: {
                                startAdornment: (
                                    <InputAdornment position="start">
                                        <IconButton
                                            size="small"
                                            onClick={(e) => setFilterAnchorEl(e.currentTarget)}
                                            sx={{ color: '#fff', bgcolor: 'primary.main', '&:hover': { bgcolor: 'primary.dark' } }}
                                            title="Change filter"
                                        >
                                            {activeFilterIcon}
                                        </IconButton>
                                    </InputAdornment>
                                ),
                                endAdornment: (
                                    <InputAdornment position="end">
                                        {searchQuery && (
                                            <IconButton size="small" onClick={handleClearSearch} disabled={isSearching}>
                                                <Clear fontSize="small" />
                                            </IconButton>
                                        )}
                                        {isSearching ? (
                                            <CircularProgress size={20} sx={{ ml: 0.5 }} />
                                        ) : (
                                            <IconButton
                                                size="small"
                                                onClick={executeSearch}
                                                disabled={searchQuery.trim().length === 0}
                                                color="primary"
                                            >
                                                <Search />
                                            </IconButton>
                                        )}
                                    </InputAdornment>
                                ),
                            }
                        }}
                    />

                    </>
                    )}

                    {/* Filter Menu — anchored to filter icon (shared across all modes) */}
                    <Menu
                        anchorEl={filterAnchorEl}
                        open={Boolean(filterAnchorEl)}
                        onClose={() => setFilterAnchorEl(null)}
                        slotProps={{ paper: { sx: { borderRadius: 2, mt: 0.5, minWidth: 200 } } }}
                    >
                        {searchKeys.map((option) => (
                            <MenuItem
                                key={option.value}
                                selected={searchKey === option.value}
                                onClick={() => {
                                    setSearchKey(option.value as any);
                                    setFilterAnchorEl(null);
                                    // Auto-set JNV and batch for non-admin users when selecting JNV & Batch filter
                                    if (option.value === 'jnvBatch' && !isAdmin && profileState?.data?.firstJnvId) {
                                        const school = Schools.find(s => s.UniqueId === profileState.data.firstJnvId);
                                        if (school) setSelectedSchoolName(`JNV ${school.SchoolName} ${school.StatePrefix}`);
                                    }
                                    if (option.value === 'jnvBatch' && !isAdmin && !isSchoolAdmin && profileState?.data?.entryYear) {
                                        setSelectedEntryYear(profileState.data.entryYear);
                                    }
                                }}
                                sx={{ py: 1 }}
                            >
                                <ListItemIcon sx={{ minWidth: 32 }}>
                                    {filterIconMap[option.value] || <TuneRounded fontSize="small" />}
                                </ListItemIcon>
                                <ListItemText>{option.label}</ListItemText>
                            </MenuItem>
                        ))}
                    </Menu>
                </Box>

                {/* Nearby geo status (coords / error) */}
                {isNearbySearch && (geoLocation.latitude > 0 || geoError) && (
                    <Box sx={{ width: '100%', maxWidth: 580, mt: 1, px: isMobile ? 1 : 0 }}>
                        {geoLocation.latitude > 0 && (
                            <Typography variant="caption" color="text.secondary" sx={{ display: 'block', textAlign: 'center' }}>
                                <LocationOnIcon sx={{ fontSize: '0.85rem', verticalAlign: 'middle', mr: 0.5 }} />
                                {geoLocation.latitude.toFixed(4)}, {geoLocation.longitude.toFixed(4)}
                            </Typography>
                        )}
                        {geoError && (
                            <Alert severity="error" sx={{ mt: 1 }}>{geoError}</Alert>
                        )}
                        {hasTriedLocationUpdate && profileState.status === CallStatus.Failure && (
                            <Alert severity="error" sx={{ mt: 1 }}>
                                {ProfileServicesError.UpdateProfileError(profileState.httpStatus)}
                            </Alert>
                        )}
                    </Box>
                )}

                {/* Subtitle text under empty state */}
                {shouldShowEmptyState && (
                    <Box sx={{ textAlign: 'center', mt: 3 }}>                        
                        <Typography variant="caption" color="text.secondary" sx={{ mt: 0.5, display: 'block' }}>
                            Tap the filter icon to search by specific fields like name, location, JNV batch, nearby &amp; more.
                        </Typography>

                        {isAdmin && (
                            <Stack direction="row" spacing={1.5} sx={{ justifyContent: 'center', mt: 2.5 }}>
                                <Chip
                                    icon={profileIndexStatus === CallStatus.InProgress ? <CircularProgress size={14} /> : <Refresh sx={{ fontSize: 16 }} />}
                                    label="Profile Index"
                                    variant="outlined"
                                    size="small"
                                    onClick={() => handleGenerateIndex('profile')}
                                    disabled={profileIndexStatus === CallStatus.InProgress}
                                    sx={{ fontSize: '0.75rem', cursor: 'pointer' }}
                                />
                                <Chip
                                    icon={businessIndexStatus === CallStatus.InProgress ? <CircularProgress size={14} /> : <Refresh sx={{ fontSize: 16 }} />}
                                    label="Business Index"
                                    variant="outlined"
                                    size="small"
                                    onClick={() => handleGenerateIndex('business')}
                                    disabled={businessIndexStatus === CallStatus.InProgress}
                                    sx={{ fontSize: '0.75rem', cursor: 'pointer' }}
                                />
                            </Stack>
                        )}

                        {indexMessage && (
                            <Alert
                                severity={indexMessage.toLowerCase().includes('failed') ? 'error' : 'success'}
                                sx={{ mt: 1, mx: 'auto', maxWidth: 400 }}
                                onClose={() => setIndexMessage('')}
                            >
                                {indexMessage}
                            </Alert>
                        )}
                    </Box>
                )}
            </Box>

            {/* Contact visibility warning */}
            {!isOwnContactVisible && shouldShowResults && hasProfileResults && (
                <Alert severity="info" icon={<VisibilityOff fontSize="small" />} sx={{ mb: 1 }}>
                    Contact details of other users will not be shown because your own contact info is set to private. <a href="/profile/edit" style={{ color: 'inherit', fontWeight: 600 }}>Make your contact info visible</a> in your profile to see others&apos; contact details.
                </Alert>
            )}

            {/* Status / Error */}
            <StatusMessage
                notStartedMessage=""
                failureMessage={error || "Search failed. Please try again."}
                currentStatus={searchStatus}
                correlationId={correlationId}
            />

            {/* Results Header */}
            {shouldShowResults && (
                <Box sx={{ px: 0.5, mb: 1 }}>
                    <Stack direction="row" sx={{ alignItems: 'center', flexWrap: 'wrap', gap: 0.5 }} spacing={0.5}>
                        <Typography variant="caption" color="text.secondary" sx={{ fontWeight: 600 }}>
                            {totalResultCount}{totalHasMore ? '+' : ''} result{totalResultCount !== 1 ? 's' : ''}
                        </Typography>
                        <Typography variant="caption" color="text.secondary">
                            for
                        </Typography>
                        <Chip
                            label={lastSearchQuery}
                            size="small"
                            variant="outlined"
                            onDelete={handleClearSearch}
                            sx={{ maxWidth: '100%', fontSize: '0.7rem', height: 22 }}
                        />
                    </Stack>
                </Box>
            )}

            {/* Profile Results */}
            {shouldShowResults && hasProfileResults && (
                <>
                    <Box sx={{ px: 0.5, mb: 0.5, mt: 1 }}>
                        <SectionHeading>Alumni ({profileResults.length}{profileHasMore ? '+' : ''})</SectionHeading>
                    </Box>
                    <InfiniteScrollList
                        items={profileResults}
                        loading={profileLoadingMore}
                        hasMore={profileHasMore}
                        loadMore={loadMoreProfiles}
                        renderItem={(profile) => <PersonDisplay key={profile.id} {...(profile as any)} isAdmin={isAdmin} />}
                    />
                </>
            )}

            {/* Business Results */}
            {shouldShowResults && hasBusinessResults && (
                <>
                    <Box sx={{ px: 0.5, mb: 0.5, mt: 1 }}>
                        <SectionHeading>Businesses ({businessResults.length}{businessHasMore ? '+' : ''})</SectionHeading>
                    </Box>
                    <InfiniteScrollList
                        items={businessResults}
                        loading={businessLoadingMore}
                        hasMore={businessHasMore}
                        loadMore={loadMoreBusinesses}
                        renderItem={(business) => <BusinessCard key={business.id} {...business} isAdmin={isAdmin} />}
                    />
                </>
            )}

            {/* No Results */}
            {shouldShowNoResults && (
                <EmptyState
                    variant="hint"
                    illustration={<SearchOff sx={{ fontSize: 48 }} />}
                    heading="No results found"
                    helper={`No results found for "${lastSearchQuery}". Try different keywords or change the filter.`}
                />
            )}
        </Box>
    );
};

export default UnifiedSearch;
