import * as React from "react";
import { Box, Chip, Paper, Typography, Stack } from "@mui/material";
import SchoolIcon from '@mui/icons-material/School';
import { compactChipSx } from '@/constants/ThemeConstants';
import { PublicProfileResult } from "@/types/profile.types";
import PlaceIcon from '@mui/icons-material/Place';
import WorkIcon from '@mui/icons-material/Work';
import LocalLibraryIcon from '@mui/icons-material/LocalLibrary';
import { ProfileType, Roles } from "@/types/api.types";
import PersonIcon from '@mui/icons-material/Person';
import EmailIcon from '@mui/icons-material/Email';
import PhoneIcon from '@mui/icons-material/Phone';
import SecurityIcon from '@mui/icons-material/Security';
import { ProfileInfoDialog } from '@/components/ProfileInfoDialog';

/** Compact icon + text row */
const InfoRow: React.FC<{ icon: React.ReactNode; children: React.ReactNode }> = ({ icon, children }) => (
  <Box sx={{ display: 'flex', alignItems: 'flex-start', gap: 0.75, minWidth: 0, py: 0.2 }}>
    <Box sx={{ color: 'action.active', display: 'flex', flexShrink: 0, mt: '2px' }}>{icon}</Box>
    <Typography variant="body2" sx={{ fontSize: '0.8125rem', wordBreak: 'break-word' }}>
      {children}
    </Typography>
  </Box>
);

const getProfileBadgeText = (profile: PublicProfileResult): string => {
  const entry = profile.entryYear > 0 ? `${profile.entryYear}` : '';
  const exit = profile.exitYear > 0 ? `${profile.exitYear}` : '';

  switch (profile.profileType) {
    case ProfileType.Alumni: 
      if (entry && exit) return `${entry}–${exit}`;
      if (!entry && exit) return `?–${exit}`;
      return entry || '';
    case ProfileType.Student: 
      if (entry) return `${entry}–Present`;
      if (exit) return `?–${exit}`;
      return '';
    case ProfileType.Staff: 
      if (entry) return `${entry}–Present`;
      return '';
    case ProfileType.ExStaff: 
      if (entry && exit) return `${entry}–${exit}`;
      if (!entry && exit) return `?–${exit}`;
      return entry || '';
    default: return '';
  }
};

const getProfileBadgeColor = (profileType: string): "default" | "primary" | "secondary" | "info" => {
  switch (profileType) {
    case ProfileType.Alumni: return 'primary';
    case ProfileType.Student: return 'info';
    case ProfileType.Staff: return 'secondary';
    case ProfileType.ExStaff: return 'default';
    default: return 'default';
  }
};

interface PersonDisplayProps extends PublicProfileResult {
  isAdmin?: boolean;
  footer?: React.ReactNode;
  /** Extra content rendered inside the card body, just below the info grid. */
  extra?: React.ReactNode;
  /** Hide location, employment and higher-education info rows (e.g. for admin role management). */
  minimal?: boolean;
  /** Roles to display when already available (no extra fetch). Shown only when non-empty. */
  roles?: Roles[];
}

export const PersonDisplay: React.FunctionComponent<PersonDisplayProps> = (props) => {
  const { isAdmin, footer, extra, minimal, roles, ...profile } = props;
  const [detailOpen, setDetailOpen] = React.useState(false);
  const canOpenDialog = isAdmin;
  const hasLocation = !minimal && profile.isContactInfoVisible && !!profile.location;
  const hasPhone = profile.isContactInfoVisible && !!profile.phone;
  const hasEmail = profile.isContactInfoVisible && !!profile.email;
  const hasEmployment = !minimal && profile.isEmploymentInfoVisible && (!!profile.jobTitle || !!profile.organisation);
  const hasEducation = !minimal && profile.isHigherEducationInfoVisible && (!!profile.degree || !!profile.university);

  const employmentText = [profile.jobTitle, profile.organisation].filter(Boolean).join(' at ');
  const educationText = [profile.degree, profile.university].filter(Boolean).join(', ');

  return (
    <Paper
      elevation={1}
      sx={{
        p: 1.5,
        mb: 1,
        borderRadius: 2,
        borderLeft: 3,
        borderColor: 'primary.light',
        transition: 'box-shadow 0.2s ease',
        '&:hover': { boxShadow: 4 },
      }}
    >
      {/* Header: Name + Badge */}
      <Stack direction="row" spacing={1} sx={{ alignItems: 'center', justifyContent: 'space-between', mb: 0.5 }}>
        <Stack direction="row" spacing={0.75} sx={{ alignItems: 'center', minWidth: 0 }}>
          <PersonIcon sx={{ fontSize: '1.1rem', color: 'primary.main' }} />
          <Typography
            variant="subtitle2"
            onClick={canOpenDialog ? () => setDetailOpen(true) : undefined}
            sx={{ fontWeight: 600, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', ...(canOpenDialog && { cursor: 'pointer', '&:hover': { textDecoration: 'underline' } }) }}
          >
            {profile.name}
          </Typography>

        </Stack>
        <Chip
          label={(() => {
            const type = profile.profileType;
            const badge = getProfileBadgeText(profile);
            const batch = profile.batch ? `Batch ${profile.batch}` : '';
            if (type && badge) return `${type} · ${badge}`;
            if (type) return type;
            if (batch) return batch;
            return '';
          })()}
          size="small"
          variant="outlined"
          color={getProfileBadgeColor(profile.profileType ?? '')}
          sx={{ flexShrink: 0, ...compactChipSx }}
        />
      </Stack>

      {/* Info grid: 2-column on desktop, 1-column on mobile */}
      <Box sx={{ display: 'grid', gridTemplateColumns: { xs: '1fr', sm: '1fr 1fr' }, gap: 0.25, ml: 0.25 }}>
        {(() => {
          const jnvText = [profile.firstJnvName, profile.otherJnvNames].filter(Boolean).join(', ');
          const locationInline = minimal && profile.isContactInfoVisible && profile.location ? profile.location : '';
          const combined = [jnvText, locationInline].filter(Boolean).join(' · ');
          return combined ? (
            <InfoRow icon={<LocalLibraryIcon sx={{ fontSize: '0.95rem' }} />}>
              {combined}
            </InfoRow>
          ) : null;
        })()}
        {hasLocation && (
          <InfoRow icon={<PlaceIcon sx={{ fontSize: '0.95rem' }} />}>
            {profile.location}
          </InfoRow>
        )}
        {hasPhone && (
          <InfoRow icon={<PhoneIcon sx={{ fontSize: '0.95rem' }} />}>
            {profile.phone}
          </InfoRow>
        )}
        {hasEmail && (
          <InfoRow icon={<EmailIcon sx={{ fontSize: '0.95rem' }} />}>
            {profile.email}
          </InfoRow>
        )}
        {hasEmployment && (
          <InfoRow icon={<WorkIcon sx={{ fontSize: '0.95rem' }} />}>
            {employmentText}
          </InfoRow>
        )}
        {hasEducation && (
          <InfoRow icon={<SchoolIcon sx={{ fontSize: '0.95rem' }} />}>
            {educationText}
          </InfoRow>
        )}
        {roles && roles.length > 0 && roles.some(r => r !== Roles.User) && (
          <InfoRow icon={<SecurityIcon sx={{ fontSize: '0.95rem' }} />}>
            {roles.filter(r => r !== Roles.User).join(', ')}
          </InfoRow>
        )}
      </Box>

      {extra && (
        <Box sx={{ mt: 0.75, ml: 0.25 }}>
          {extra}
        </Box>
      )}

      {footer && (
        <Box sx={{ mt: 1, pt: 1, borderTop: '1px solid', borderColor: 'divider' }}>
          {footer}
        </Box>
      )}

      {canOpenDialog && (
        <ProfileInfoDialog
          open={detailOpen}
          profileId={profile.id}
          mode={isAdmin ? 'admin' : 'public'}
          onClose={() => setDetailOpen(false)}
        />
      )}
    </Paper>
  );
};